#!/usr/bin/env python3\n\"\"\"\nTracePort Quick Start Demo\nDemonstrates basic scanning functionality\n\"\"\"\n\nfrom traceport.scanner import PortScanner\nfrom traceport.models import ScanResult\nimport json\n\ndef print_header(title):\n    print(\"\\n\" + \"=\"*70)\n    print(f\"  {title}\")\n    print(\"=\"*70 + \"\\n\")\n\ndef demo_basic_scan():\n    \"\"\"Demo 1: Basic localhost scan\"\"\"\n    print_header(\"DEMO 1: Basic Port Scan\")\n    \n    print(\"Creating scanner with default settings...\")\n    scanner = PortScanner(max_threads=50, timeout=2, banner_grab=True)\n    \n    print(\"Scanning localhost for common ports...\\n\")\n    result = scanner.scan(\"localhost\", port_range=\"1-1024\")\n    \n    print(f\"Target: {result.target}\")\n    print(f\"IP Address: {result.ip_address}\")\n    print(f\"Ports Scanned: {result.total_ports_scanned}\")\n    print(f\"Open Ports Found: {result.open_ports_count}\")\n    print(f\"Scan Duration: {result.scan_duration:.2f} seconds\")\n    print(f\"Status: {result.status}\")\n    \n    if result.open_ports:\n        print(f\"\\nOpen Ports: {', '.join(map(str, result.open_ports[:10]))}\")\n        if len(result.open_ports) > 10:\n            print(f\"... and {len(result.open_ports) - 10} more\")\n    \n    return result\n\ndef demo_custom_ports():\n    \"\"\"Demo 2: Custom port selection\"\"\"\n    print_header(\"DEMO 2: Custom Port Selection\")\n    \n    scanner = PortScanner(max_threads=100, timeout=1, banner_grab=False)\n    \n    custom_ports = [22, 80, 443, 3306, 5432, 8080, 8443, 27017, 6379]\n    print(f\"Scanning specific ports: {custom_ports}\\n\")\n    \n    result = scanner.scan(\"127.0.0.1\", ports=custom_ports)\n    \n    print(f\"Target: {result.target}\")\n    print(f\"Open Ports: {result.open_ports if result.open_ports else 'None'}\")\n    print(f\"Scan Duration: {result.scan_duration:.2f} seconds\")\n    \n    return result\n\ndef demo_port_range():\n    \"\"\"Demo 3: Port range scanning\"\"\"\n    print_header(\"DEMO 3: Port Range Scanning\")\n    \n    scanner = PortScanner(max_threads=150, timeout=1.5, banner_grab=True)\n    \n    port_ranges = \"20-25,80,443,3000-3010,8000-8010,9000-9010\"\n    print(f\"Scanning port range: {port_ranges}\\n\")\n    \n    result = scanner.scan(\"localhost\", port_range=port_ranges)\n    \n    print(f\"Target: {result.target}\")\n    print(f\"Total Ports Scanned: {result.total_ports_scanned}\")\n    print(f\"Open Ports: {result.open_ports if result.open_ports else 'None'}\")\n    print(f\"Services Found: {len(result.services)}\")\n    \n    if result.services:\n        print(\"\\nService Details:\")\n        for svc in result.services[:5]:\n            print(f\"  Port {svc.port}: {svc.service_name} {svc.version or ''}\")\n    \n    return result\n\ndef demo_progress_callback():\n    \"\"\"Demo 4: Real-time progress tracking\"\"\"\n    print_header(\"DEMO 4: Progress Tracking\")\n    \n    def on_progress(completed, total):\n        percentage = (completed / total) * 100\n        bar_length = 40\n        filled = int(bar_length * completed / total)\n        bar = '█' * filled + '░' * (bar_length - filled)\n        print(f\"\\rScanning: [{bar}] {percentage:.1f}% ({completed}/{total})\", end='', flush=True)\n    \n    scanner = PortScanner(max_threads=100, timeout=1, banner_grab=False)\n    scanner.set_progress_callback(on_progress)\n    \n    print(\"Scanning with progress callback...\\n\")\n    result = scanner.scan(\"localhost\", port_range=\"1-500\")\n    \n    print(f\"\\n\\nScan Complete!\")\n    print(f\"Open Ports: {result.open_ports_count}\")\n    print(f\"Total Duration: {result.scan_duration:.2f} seconds\")\n    \n    return result\n\ndef demo_export_results():\n    \"\"\"Demo 5: Export results to different formats\"\"\"\n    print_header(\"DEMO 5: Export Results\")\n    \n    scanner = PortScanner(max_threads=100, timeout=2, banner_grab=True)\n    \n    print(\"Performing scan...\")\n    result = scanner.scan(\"localhost\", port_range=\"1-500\")\n    \n    # JSON export\n    print(\"\\nExporting to JSON format...\")\n    json_data = result.to_json()\n    print(f\"JSON Output (truncated):\\n{json_data[:300]}...\")\n    \n    # Dictionary export\n    print(\"\\n\" + \"=\"*70)\n    print(\"\\nExporting to dictionary format...\")\n    dict_data = result.to_dict()\n    print(f\"Dictionary Keys: {list(dict_data.keys())}\")\n    print(f\"Open Ports Count: {dict_data['open_ports_count']}\")\n    print(f\"Scan Duration: {dict_data['scan_duration']:.2f}s\")\n    \n    return result\n\ndef demo_batch_scanning():\n    \"\"\"Demo 6: Multiple target scanning\"\"\"\n    print_header(\"DEMO 6: Batch Scanning\")\n    \n    targets = [\"localhost\", \"127.0.0.1\"]\n    results = []\n    \n    scanner = PortScanner(max_threads=100, timeout=2, banner_grab=False)\n    \n    print(f\"Scanning {len(targets)} targets...\\n\")\n    \n    for i, target in enumerate(targets, 1):\n        print(f\"[{i}/{len(targets)}] Scanning {target}...\")\n        result = scanner.scan(target, port_range=\"1-500\")\n        results.append({\n            'target': result.target,\n            'ip': result.ip_address,\n            'open_ports': result.open_ports_count,\n            'duration': result.scan_duration\n        })\n        print(f\"  Found {result.open_ports_count} open ports in {result.scan_duration:.2f}s\")\n    \n    # Summary\n    print(\"\\n\" + \"-\"*70)\n    print(\"BATCH SUMMARY\")\n    print(\"-\"*70)\n    for res in results:\n        print(f\"{res['target']:20} | Open Ports: {res['open_ports_count']:3} | Duration: {res['duration']:.2f}s\")\n    \n    return results\n\ndef demo_performance_comparison():\n    \"\"\"Demo 7: Performance comparison with different settings\"\"\"\n    print_header(\"DEMO 7: Performance Comparison\")\n    \n    configs = [\n        {\"name\": \"Conservative\", \"threads\": 50, \"timeout\": 3, \"banner\": False},\n        {\"name\": \"Balanced\", \"threads\": 100, \"timeout\": 2, \"banner\": False},\n        {\"name\": \"Aggressive\", \"threads\": 200, \"timeout\": 1, \"banner\": False},\n    ]\n    \n    results = []\n    port_range = \"1-500\"\n    \n    print(f\"Comparing performance with port range: {port_range}\\n\")\n    \n    for config in configs:\n        print(f\"Testing {config['name']} configuration...\")\n        scanner = PortScanner(\n            max_threads=config['threads'],\n            timeout=config['timeout'],\n            banner_grab=config['banner']\n        )\n        \n        result = scanner.scan(\"localhost\", port_range=port_range)\n        \n        results.append({\n            'config': config['name'],\n            'threads': config['threads'],\n            'timeout': config['timeout'],\n            'duration': result.scan_duration,\n            'ports_found': result.open_ports_count\n        })\n        \n        print(f\"  Duration: {result.scan_duration:.2f}s, Open Ports: {result.open_ports_count}\\n\")\n    \n    # Comparison table\n    print(\"\\n\" + \"-\"*70)\n    print(\"PERFORMANCE COMPARISON\")\n    print(\"-\"*70)\n    print(f\"{'Configuration':<15} {'Threads':<10} {'Timeout':<10} {'Duration':<12} {'Ports'}\")\n    print(\"-\"*70)\n    for res in results:\n        print(f\"{res['config']:<15} {res['threads']:<10} {res['timeout']:<10} {res['duration']:<12.2f} {res['ports_found']}\")\n\ndef demo_error_handling():\n    \"\"\"Demo 8: Error handling and edge cases\"\"\"\n    print_header(\"DEMO 8: Error Handling\")\n    \n    scanner = PortScanner(timeout=2)\n    \n    # Test invalid hostname\n    print(\"Test 1: Scanning invalid hostname...\")\n    result = scanner.scan(\"invalid-hostname-that-does-not-exist-12345.com\", port_range=\"80,443\")\n    print(f\"Status: {result.status}\")\n    print(f\"Error: {result.error_message}\\n\")\n    \n    # Test empty port list (should use common ports)\n    print(\"Test 2: Scanning with no ports specified...\")\n    result = scanner.scan(\"localhost\")\n    print(f\"Status: {result.status}\")\n    print(f\"Total ports scanned: {result.total_ports_scanned}\")\n    print(f\"Open ports: {result.open_ports_count}\\n\")\n    \n    # Test valid target\n    print(\"Test 3: Scanning localhost (valid target)...\")\n    result = scanner.scan(\"localhost\", ports=[80, 443])\n    print(f\"Status: {result.status}\")\n    print(f\"Open ports: {result.open_ports if result.open_ports else 'None'}\")\n\ndef main():\n    \"\"\"Run all demos\"\"\"\n    print(\"\\n\")\n    print(\"╔\" + \"═\"*68 + \"╗\")\n    print(\"║\" + \" \"*15 + \"TracePort - COMPREHENSIVE DEMO\" + \" \"*23 + \"║\")\n    print(\"║\" + \" \"*12 + \"High-Performance Network Port Scanner\" + \" \"*20 + \"║\")\n    print(\"╚\" + \"═\"*68 + \"╝\")\n    \n    demos = [\n        (\"1\", \"Basic Port Scan\", demo_basic_scan),\n        (\"2\", \"Custom Ports\", demo_custom_ports),\n        (\"3\", \"Port Range Scanning\", demo_port_range),\n        (\"4\", \"Progress Tracking\", demo_progress_callback),\n        (\"5\", \"Export Results\", demo_export_results),\n        (\"6\", \"Batch Scanning\", demo_batch_scanning),\n        (\"7\", \"Performance Comparison\", demo_performance_comparison),\n        (\"8\", \"Error Handling\", demo_error_handling),\n    ]\n    \n    print(\"\\nAvailable Demos:\")\n    print(\"-\" * 50)\n    for num, desc, _ in demos:\n        print(f\"  {num}. {desc}\")\n    \n    print(f\"\\n  A. Run All Demos\")\n    print(f\"  Q. Exit\")\n    print(\"-\" * 50)\n    \n    choice = input(\"\\nSelect demo to run (1-8, A, or Q): \").strip().upper()\n    \n    if choice == 'Q':\n        print(\"\\nExiting demo...\")\n        return\n    \n    if choice == 'A':\n        for num, desc, demo_func in demos:\n            try:\n                demo_func()\n            except Exception as e:\n                print(f\"\\nError in {desc}: {str(e)}\")\n            input(\"\\nPress Enter to continue to next demo...\")\n    else:\n        for num, desc, demo_func in demos:\n            if num == choice:\n                try:\n                    demo_func()\n                except Exception as e:\n                    print(f\"\\nError: {str(e)}\")\n                break\n    \n    print_header(\"Demo Complete!\")\n    print(\"Thank you for using TracePort!\")\n    print(\"\\nFor more information, visit: https://github.com/PasinduW-sketch/TracePort\")\n    print()\n\nif __name__ == \"__main__\":\n    main()\n"